class UserProfileService {
  async saveProfile(profileData) {
    const sanitizedProfile = {
      id: profileData.id,
      email: profileData.email,
      firstName: profileData.firstName,
      lastName: profileData.lastName,
      phone: profileData.phone,
      address: profileData.address,
      dateOfBirth: profileData.dateOfBirth,
      avatarUrl: profileData.avatarUrl,
      updatedAt: new Date().toISOString(),
      checksum: encryptionService.hashData(
        JSON.stringify({
          id: profileData.id,
          email: profileData.email,
        })
      ),
    };

    await secureStorage.setItem(StorageKeys.USER_PROFILE, sanitizedProfile);
    return sanitizedProfile;
  }

  async getProfile() {
    const profile = await secureStorage.getItem(StorageKeys.USER_PROFILE);
    if (!profile) return null;

    const expectedChecksum = encryptionService.hashData(
      JSON.stringify({
        id: profile.id,
        email: profile.email,
      })
    );

    if (profile.checksum !== expectedChecksum) {
      console.warn('Profile data integrity check failed');
      await this.deleteProfile();
      return null;
    }

    return profile;
  }

  async updateProfile(partialData) {
    const existingProfile = await this.getProfile();
    if (!existingProfile) {
      throw new Error('No existing profile found to update');
    }

    const updatedProfile = {
      ...existingProfile,
      ...partialData,
      updatedAt: new Date().toISOString(),
    };

    return this.saveProfile(updatedProfile);
  }

  async deleteProfile() {
    await secureStorage.removeItem(StorageKeys.USER_PROFILE);
  }

  async hasProfile() {
    return secureStorage.hasItem(StorageKeys.USER_PROFILE);
  }
}

