class PaymentService {
  _maskCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (cleaned.length < 4) return '****';
    return `****${cleaned.slice(-4)}`;
  }

  _validateCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (!/^\d{13,19}$/.test(cleaned)) return false;

    let sum = 0;
    let isEven = false;
    for (let i = cleaned.length - 1; i >= 0; i--) {
      let digit = parseInt(cleaned[i], 10);
      if (isEven) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      isEven = !isEven;
    }
    return sum % 10 === 0;
  }

  async savePaymentInfo(paymentData) {
    if (paymentData.cardNumber && !this._validateCardNumber(paymentData.cardNumber)) {
      throw new Error('Invalid card number');
    }

    const securePaymentData = {
      id: paymentData.id || encryptionService.generateRandomToken(16),
      cardholderName: paymentData.cardholderName,
      cardNumberHash: encryptionService.hashData(paymentData.cardNumber),
      cardNumberMasked: this._maskCardNumber(paymentData.cardNumber),
      cardNumberEncrypted: paymentData.cardNumber,
      expiryMonth: paymentData.expiryMonth,
      expiryYear: paymentData.expiryYear,
      cardType: this._detectCardType(paymentData.cardNumber),
      billingAddress: paymentData.billingAddress || null,
      isDefault: paymentData.isDefault || false,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    const existingCards = await this.getAllPaymentMethods();
    const cardIndex = existingCards.findIndex((c) => c.id === securePaymentData.id);

    if (cardIndex >= 0) {
      existingCards[cardIndex] = securePaymentData;
    } else {
      existingCards.push(securePaymentData);
    }

    if (securePaymentData.isDefault) {
      existingCards.forEach((card) => {
        if (card.id !== securePaymentData.id) {
          card.isDefault = false;
        }
      });
    }

    await secureStorage.setItem(StorageKeys.PAYMENT_INFO, existingCards);
    return {
      ...securePaymentData,
      cardNumberEncrypted: undefined,
    };
  }

  _detectCardType(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (/^4/.test(cleaned)) return 'visa';
    if (/^5[1-5]/.test(cleaned) || /^2[2-7]/.test(cleaned)) return 'mastercard';
    if (/^3[47]/.test(cleaned)) return 'amex';
    if (/^6(?:011|5)/.test(cleaned)) return 'discover';
    if (/^35(?:2[89]|[3-8])/.test(cleaned)) return 'jcb';
    if (/^3(?:0[0-5]|[68])/.test(cleaned)) return 'dinersclub';
    return 'unknown';
  }

  async getAllPaymentMethods() {
    const cards = await secureStorage.getItem(StorageKeys.PAYMENT_INFO);
    return cards || [];
  }

  async getPaymentMethodSummaries() {
    const cards = await this.getAllPaymentMethods();
    return cards.map((card) => ({
      id: card.id,
      cardholderName: card.cardholderName,
      cardNumberMasked: card.cardNumberMasked,
      expiryMonth: card.expiryMonth,
      expiryYear: card.expiryYear,
      cardType: card.cardType,
      isDefault: card.isDefault,
    }));
  }

  async getFullPaymentMethod(cardId) {
    const cards = await this.getAllPaymentMethods();
    return cards.find((c) => c.id === cardId) || null;
  }

  async deletePaymentMethod(cardId) {
    const cards = await this.getAllPaymentMethods();
    const filtered = cards.filter((c) => c.id !== cardId);
    await secureStorage.setItem(StorageKeys.PAYMENT_INFO, filtered);
    return true;
  }

  async deleteAllPaymentMethods() {
    await secureStorage.removeItem(StorageKeys.PAYMENT_INFO);
    return true;
  }

  async setDefaultPaymentMethod(cardId) {
    const cards = await this.getAllPaymentMethods();
    const updatedCards = cards.map((card) => ({
      ...card,
      isDefault: card.id === cardId,
    }));
    await secureStorage.setItem(StorageKeys.PAYMENT_INFO, updatedCards);
    return true;
  }
}

