import secureStorage, { StorageKeys } from '../utils/secureStorage';
import encryptionService from '../utils/encryptionService';

class AuthTokenService {
  async saveAuthTokens(tokens) {
    const tokenData = {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      tokenType: tokens.tokenType || 'Bearer',
      expiresIn: tokens.expiresIn,
      expiresAt: tokens.expiresAt || Date.now() + (tokens.expiresIn || 3600) * 1000,
      scope: tokens.scope || '',
      sessionId: tokens.sessionId || encryptionService.generateRandomToken(24),
      createdAt: Date.now(),
      fingerprint: encryptionService.hashData(
        `${tokens.accessToken}_${Date.now()}`
      ),
    };

    await secureStorage.setMultiple([
      [StorageKeys.AUTH_TOKEN, tokenData],
      [
        StorageKeys.SESSION_DATA,
        {
          sessionId: tokenData.sessionId,
          loginTime: tokenData.createdAt,
          lastActivity: Date.now(),
        },
      ],
    ]);

    return tokenData;
  }

  async getAccessToken() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData) return null;

    if (this._isTokenExpired(tokenData)) {
      return null;
    }

    return tokenData.accessToken;
  }

  async getRefreshToken() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData) return null;
    return tokenData.refreshToken;
  }

  async getAuthHeader() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData) return null;

    if (this._isTokenExpired(tokenData)) {
      return null;
    }

    return `${tokenData.tokenType} ${tokenData.accessToken}`;
  }

  async getTokenData() {
    return secureStorage.getItem(StorageKeys.AUTH_TOKEN);
  }

  _isTokenExpired(tokenData) {
    if (!tokenData.expiresAt) return false;
    const bufferMs = 60000; // 1 minute buffer
    return Date.now() >= tokenData.expiresAt - bufferMs;
  }

  async isAuthenticated() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData) return false;
    return !this._isTokenExpired(tokenData);
  }

  async getTimeUntilExpiry() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData || !tokenData.expiresAt) return 0;
    const remaining = tokenData.expiresAt - Date.now();
    return Math.max(0, remaining);
  }

  async updateTokens(newTokens) {
    const existingData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!existingData) {
      return this.saveAuthTokens(newTokens);
    }

    const updatedData = {
      ...existingData,
      accessToken: newTokens.accessToken || existingData.accessToken,
      refreshToken: newTokens.refreshToken || existingData.refreshToken,
      expiresIn: newTokens.expiresIn || existingData.expiresIn,
      expiresAt:
        newTokens.expiresAt ||
        Date.now() + (newTokens.expiresIn || existingData.expiresIn || 3600) * 1000,
      fingerprint: encryptionService.hashData(
        `${newTokens.accessToken || existingData.accessToken}_${Date.now()}`
      ),
    };

    await secureStorage.setItem(StorageKeys.AUTH_TOKEN, updatedData);
    return updatedData;
  }

  async updateLastActivity() {
    const sessionData = await secureStorage.getItem(StorageKeys.SESSION_DATA);
    if (sessionData) {
      sessionData.lastActivity = Date.now();
      await secureStorage.setItem(StorageKeys.SESSION_DATA, sessionData);
    }
  }

  async getSessionData() {
    return secureStorage.getItem(StorageKeys.SESSION_DATA);
  }

  async clearAuthData() {
    await secureStorage.removeMultiple([
      StorageKeys.AUTH_TOKEN,
      StorageKeys.REFRESH_TOKEN,
      StorageKeys.SESSION_DATA,
    ]);
    return true;
  }

  async logout() {
    await secureStorage.clearAll();
    return true;
  }
}

const authTokenService = new AuthTokenService();
export default authTokenService;

// hooks/useSecureStorage.js
import { useState, useEffect, useCallback } from 'react';
import secureStorage from '../utils/secureStorage';

export function useSecureStorage(key, initialValue = null) {
  const [storedValue, setStoredValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadValue = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const value = await secureStorage.getItem(key);
      setStoredValue(value !== null ? value : initialValue);
    } catch (err) {
      setError(err);
      console.error(`useSecureStorage load error for key ${key}:`, err);
    } finally {
      setLoading(false);
    }
  }, [key, initialValue]);

  useEffect(() => {
    loadValue();
  }, [loadValue]);

  const setValue = useCallback(
    async (value) => {
      try {
        setError(null);
        const valueToStore = value instanceof Function ? value(storedValue) : value;
        await secureStorage.setItem(key, valueToStore);
        setStoredValue(valueToStore);
        return true;
      } catch (err) {
        setError(err);
        console.error(`useSecureStorage set error for key ${key}:`, err);
        return false;
      }
    },
    [key, storedValue]
  );

  const removeValue = useCallback(async () => {
    try {
      setError(null);
      await secureStorage.removeItem(key);
      setStoredValue(initialValue);
      return true;
    } catch (err) {
      setError(err);
      console.error(`useSecureStorage remove error for key ${key}:`, err);
      return false;
    }
  }, [key, initialValue]);

  const refresh = useCallback(() => {
    return loadValue();
  }, [loadValue]);

  return {
    value: storedValue,
    setValue,
    removeValue,
    refresh,
    loading,
    error,
  };
}

export function useAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [tokenData, setTokenData] = useState(null);

  const authTokenService = require('../services/authTokenService').default;

  const checkAuth = useCallback(async () => {
    try {
      setLoading(true);
      const authenticated = await authTokenService.isAuthenticated();
      setIsAuthenticated(authenticated);
      if (authenticated) {
        const data = await authTokenService.getTokenData();
        setTokenData(data);
      } else {
        setTokenData(null);
      }
    } catch (err) {
      setIsAuthenticated(false);
      setTokenData(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  const login = useCallback(async (tokens) => {
    const data = await authTokenService.saveAuthTokens(tokens);
    setIsAuthenticated(true);
    setTokenData(data);
    return data;
  }, []);

  const logout = useCallback(async () => {
    await authTokenService.logout();
    setIsAuthenticated(false);
    setTokenData(null);
  }, []);

  const refreshTokens = useCallback(async (newTokens) => {
    const data = await authTokenService.updateTokens(newTokens);
    setTokenData(data);
    return data;
  }, []);

  return {
    isAuthenticated,
    tokenData,
    loading,
    login,
    logout,
    refreshTokens,
    checkAuth,
  };
}

